/* =========================================
   GLOBAL VARIABLES & CONSTANTS
========================================= */
const texts = [
  "Building Fast Websites!",
  "Crafting Modern UIs!",
  "Responsive Web Experiences!"
];


const TYPE_SPEED = 120;
const DELETE_SPEED = 60;
const PAUSE_TIME = 1800;

let textIndex = 0;
let charIndex = 0;
let isDeleting = false;
let typingTimeout;

/* =========================================
     HEADER: THEME TOGGLE (Dark/Light)
========================================= */
function initializeTheme() {
  const toggle = document.getElementById("theme");
  if (!toggle) return;

  const lightMode = localStorage.getItem("lightMode") === "true";

  if (lightMode) {
    document.body.classList.add("light-mode");
    toggle.checked = true;
  }

  toggle.addEventListener("change", () => {
    document.body.classList.toggle("light-mode");
    localStorage.setItem(
      "lightMode",
      document.body.classList.contains("light-mode")
    );
  });
}

/* =========================================
     HEADER: MOBILE MENU (Hamburger)
========================================= */
function initializeMobileMenu() {
  const hamburger = document.getElementById("toggle_button");
  const navMenu = document.getElementById("nav-menu");

  if (!hamburger || !navMenu) return;

  const navLinks = document.querySelectorAll("#nav-menu a");

  const closeMenu = () => {
    navMenu.classList.remove("nav-active");
    hamburger.classList.remove("fa-xmark");
    hamburger.classList.add("fa-bars");
  };

  hamburger.addEventListener("click", () => {
    navMenu.classList.toggle("nav-active");
    hamburger.classList.toggle("fa-bars");
    hamburger.classList.toggle("fa-xmark");
  });

  navLinks.forEach(link => {
    link.addEventListener("click", closeMenu);
  });


  document.addEventListener("click", (e) => {
    if (!navMenu.contains(e.target) && !hamburger.contains(e.target) && navMenu.classList.contains("nav-active")) {
      closeMenu();
    }
  });


  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && navMenu.classList.contains("nav-active")) {
      closeMenu();
    }
  });
}

/* =========================================
     NAVIGATION: ACTIVE LINK SPY
========================================= */
function initializeActiveLinks() {
  const sections = document.querySelectorAll("section[id]");
  const navLinks = document.querySelectorAll(".nav-link"); // Optimization: Query outside the loop

  if (!sections.length || !navLinks.length) return;

  const observer = new IntersectionObserver(
    entries => {
      entries.forEach(entry => {
        // Jab bhi koi section screen ke upper part mein aayega, ye true ho jayega
        if (entry.isIntersecting) {
          const id = entry.target.id;
          
          navLinks.forEach(link => {
            link.classList.remove("active-link");
            if (link.getAttribute("href") === `#${id}`) {
              link.classList.add("active-link");
            }
          });
        }
      });
    },
    { rootMargin: "-20% 0px -60% 0px", threshold: 0 } 
  );

  sections.forEach(section => observer.observe(section));
}

/* =========================================
      HERO SECTION: TYPING EFFECT
========================================= */
function typeEffect() {
  const textElement = document.querySelector(".textEffect");
  const cursorElement = document.querySelector(".last");

  if (!textElement || !cursorElement) return;

  const currentText = texts[textIndex];

  if (isDeleting) {
    charIndex--;
  } else {
    charIndex++;
  }

  textElement.textContent = currentText.slice(0, charIndex);

  if (!isDeleting && charIndex === currentText.length) {
    cursorElement.textContent = "";
    typingTimeout = setTimeout(() => {
      isDeleting = true;
      typeEffect();
    }, PAUSE_TIME);
    return;
  }

  if (isDeleting && charIndex === 0) {
    isDeleting = false;
    textIndex = (textIndex + 1) % texts.length;
    cursorElement.textContent = "|";
  }

  typingTimeout = setTimeout(
    typeEffect,
    isDeleting ? DELETE_SPEED : TYPE_SPEED
  );
}

/* =========================================
     PROJECTS SECTION: CUSTOM SLIDER
========================================= */
function initializeProjectSlider() {
  const slider = document.getElementById('projectSlider');
  const slideLeft = document.getElementById('slideLeft');
  const slideRight = document.getElementById('slideRight');
  const dots = document.querySelectorAll('.slider-dot');

  if (slider && slideLeft && slideRight) {


    const moveRight = () => {

      let isAtEnd = Math.ceil(slider.scrollLeft) >= (slider.scrollWidth - slider.clientWidth - 5);

      if (isAtEnd) {
        slider.scrollTo({ left: 0, behavior: 'smooth' });
        return;
      }

      slider.scrollBy({ left: slider.clientWidth / 1.5, behavior: 'smooth' });
    };

    slideRight.addEventListener('click', moveRight);


    slideLeft.addEventListener('click', () => {
      let isAtStart = slider.scrollLeft <= 5;

      if (isAtStart) {
        slider.scrollTo({ left: slider.scrollWidth, behavior: 'smooth' });
        return;
      }

      slider.scrollBy({ left: -(slider.clientWidth / 1.5), behavior: 'smooth' });
    });

    slider.addEventListener('scroll', () => {
      const cardWidth = slider.firstElementChild ? slider.firstElementChild.offsetWidth : slider.clientWidth;
      let scrollIndex = Math.round(slider.scrollLeft / cardWidth);

      dots.forEach((dot, index) => {
        dot.classList.toggle('active', index === scrollIndex);
      });
    });

    dots.forEach((dot, index) => {
      dot.addEventListener('click', () => {
        const cardWidth = slider.firstElementChild ? slider.firstElementChild.offsetWidth : slider.clientWidth;
        slider.scrollTo({ left: cardWidth * index, behavior: 'smooth' });
      });
    });


    let autoPlay = setInterval(moveRight, 3000);

    slider.addEventListener('mouseenter', () => clearInterval(autoPlay));
    slider.addEventListener('mouseleave', () => {
      autoPlay = setInterval(moveRight, 3000);
    });
  }
}

/* =========================================
     CONTACT SECTION: FORM SUBMISSION
========================================= */
function initializeContactForm() {
  const form = document.getElementById("contactForm");
  if (!form) return;

  form.addEventListener("submit", async e => {
    e.preventDefault();
    const button = form.querySelector(".form-submit-btn");
    const successMsg = document.getElementById("successMsg");

    if (button.disabled) return;

    button.disabled = true;
    button.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Sending...';

    try {
      const response = await fetch(form.action, {
        method: "POST",
        body: new FormData(form),
        headers: { Accept: "application/json" }
      });

      if (!response.ok) throw new Error("Form submission failed");

      form.reset();
      button.innerHTML = '<i class="fa-solid fa-check"></i> Sent Successfully';
      if (successMsg) successMsg.style.display = "block";

      setTimeout(() => {
        button.disabled = false;
        button.innerHTML = '<i class="fa-regular fa-paper-plane"></i> Send Message';
        if (successMsg) successMsg.style.display = "none";
      }, 4000);
    } catch (error) {
      button.disabled = false;
      button.innerHTML = '<i class="fa-solid fa-triangle-exclamation"></i> Try Again';
      alert("Failed to send message. Please check your connection and try again.");
    }
  });
}

/* =========================================
     LOADER FALLBACK
========================================= */
function initializeLoader() {
  const loader = document.getElementById("loader");
  if (!loader) return;

  setTimeout(() => {
    if (!loader.classList.contains("hide")) {
      loader.classList.add("hide");
    }
  }, 2000);
}

/* =========================================
     EVENTS: DOMContentLoaded, Load & Unload
========================================= */
document.addEventListener("DOMContentLoaded", () => {
  if (typeof AOS !== "undefined") {
    AOS.init({
      once: false,
      duration: 500
    });
  }

  initializeTheme();
  initializeMobileMenu();
  initializeActiveLinks();
  initializeProjectSlider();
  initializeContactForm();
  initializeLoader();
  typeEffect();
});

window.addEventListener("load", () => {
  document.body.style.transition = "background-color .5s, color .5s";

  if (typeof AOS !== "undefined") {
    AOS.refresh();
  }
});

window.addEventListener("beforeunload", () => {
  clearTimeout(typingTimeout);
});
